export function getAlliedHealthProfession(slug: string): AlliedHealthProfession | undefined {
  return ALLIED_HEALTH_PROFESSIONS.find(p => p.slug === slug);
}

export function getAlliedHealthProfessionSlugs(): string[] {
  return ALLIED_HEALTH_PROFESSIONS.map(p => p.slug);
}
